description:
Implement the CompileExt trait that provides the compile() method on all Signature types.

Location: crates/dspy-rs/src/signature/compiled.rs

```rust
/// Extension trait for compiling signatures
pub trait CompileExt: Signature {
    /// Compile this signature for prompt rendering
    fn compile() -> CompiledSignature<Self>;
}

impl<T: Signature> CompileExt for T {
    fn compile() -> CompiledSignature<Self> {
        // 1. Build a Registry
        let mut registry = Registry::new();

        // 2. Register Input and Output types
        <Self::Input as BamlType>::register(&mut registry);
        <Self::Output as BamlType>::register(&mut registry);

        // 3. Build with renderers
        // (target doesn't matter for the db, only for schema rendering)
        let (output_format, renderer_seed) = registry.build_with_renderers(TypeIR::string());

        // 4. Create PromptWorld
        let world = Arc::new(PromptWorld::from_registry(
            output_format,
            renderer_seed,
            RenderSettings::default(),
        ).expect('failed to build prompt world'));

        // 5. Build SigMeta
        let sig_meta = SigMeta::from_signature::<Self>();

        // 6. Register default templates in world.jinja
        let system_template = 'sig::system'.to_string();
        let user_template = 'sig::user'.to_string();

        // Note: templates registered in world construction or here

        CompiledSignature {
            world,
            system_template,
            user_template,
            sig_meta,
            _phantom: std::marker::PhantomData,
        }
    }
}
```

This makes compiling a signature as simple as: let compiled = MySignature::compile();
